// Generates the Python hashlib demo shown on the Done step.

export function full_script(state) {
  const messageLiteral = JSON.stringify(state.sha_message ?? "hello, world");
  return [
    "# SHA-256 demo — generated by cloak.moosha.org",
    "# hashlib ships with Python — no third-party install required.",
    "#",
    "# Where SHA-256 actually shows up in production:",
    "#   - TLS certificate fingerprints (the long hex string in your browser's",
    "#     'View Certificate' dialog is usually a SHA-256 of the cert DER bytes).",
    "#   - File integrity checksums (download verification, OS package managers).",
    "#   - Git: every commit, tree, and blob is addressed by its SHA-1 today,",
    "#     migrating to SHA-256 — same Merkle-tree idea.",
    "#   - Password hashing — but NOT raw SHA-256. Use PBKDF2 (also in hashlib),",
    "#     bcrypt, scrypt, or Argon2; they iterate a hash thousands of times",
    "#     to slow down brute-force attacks.",
    "#   - HMAC-SHA-256 for message authentication (next lesson).",
    "",
    "import hashlib",
    "",
    "# 1. Hash your message.",
    `message = b${messageLiteral}`,
    "digest = hashlib.sha256(message).hexdigest()",
    'print("message:", message.decode())',
    'print("sha256 :", digest)',
    "",
    "# 2. The canonical empty-string test vector — every SHA-256 implementation",
    "#    on Earth produces the same value for this input.",
    'empty = hashlib.sha256(b"").hexdigest()',
    'assert empty == "e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855"',
    'print("sha256(\\"\\"):", empty)',
    "",
    "# 3. Avalanche: a 1-bit input change flips ~50% of the output bits.",
    '#    Compare the digests of "hello" and "Hello".',
    'h1 = hashlib.sha256(b"hello").hexdigest()',
    'h2 = hashlib.sha256(b"Hello").hexdigest()',
    'print("hello  :", h1)',
    'print("Hello  :", h2)',
    "",
    "# Count differing bits between the two digests (XOR + popcount).",
    "diff = int(h1, 16) ^ int(h2, 16)",
    "print(f\"differing bits: {bin(diff).count('1')} of 256\")",
  ].join("\n");
}

